import React, { useEffect, useState } from "react";
import axios from "axios";
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  BarChart,
  Bar,
  Legend,
} from "recharts";
import "./PriceAnalytics.css";

const API_URL = "http://localhost:7000/api/products";
const CATEGORY_URL = "http://localhost:7000/api/categories";

export default function PriceAnalytics() {
  const [productList, setProductList] = useState([]);
  const [categories, setCategories] = useState([]);
  const [newCategory, setNewCategory] = useState("");

  // Fetch Products
  const fetchProducts = async () => {
    try {
      const res = await axios.get(API_URL);
      const data = Array.isArray(res.data)
        ? res.data
        : res.data.data || [];
      setProductList(data);
    } catch (err) {
      console.error("Error fetching products:", err);
      setProductList([]);
    }
  };

  // Fetch Categories
  const fetchCategories = async () => {
    try {
      const res = await axios.get(CATEGORY_URL);
      const data = Array.isArray(res.data)
        ? res.data
        : res.data.data || [];
      setCategories(data);
    } catch (err) {
      console.error("Error fetching categories:", err);
    }
  };

  // Add Category
  const handleAddCategory = async (e) => {
    e.preventDefault();
    if (!newCategory.trim()) return alert("Please enter category name!");
    try {
      await axios.post(CATEGORY_URL, { name: newCategory });
      setNewCategory("");
      fetchCategories();
      alert("Category added successfully!");
    } catch (err) {
      console.error("Error adding category:", err);
      alert("Failed to add category.");
    }
  };

  useEffect(() => {
    fetchProducts();
    fetchCategories();
  }, []);

  // Sample chart data
  const chartData = productList.map((p, index) => ({
    name: p.name || `Item ${index + 1}`,
    price: p.price || Math.floor(Math.random() * 500),
    stock: p.stock || Math.floor(Math.random() * 100),
  }));

  return (
    <div className="analytics-container">
      <h2 className="analytics-title">📊 Price Analytics Dashboard</h2>

      {/* Add Category Section */}
      <div className="category-add-box">
        <form onSubmit={handleAddCategory} className="category-form">
          <input
            type="text"
            placeholder="Enter category name..."
            value={newCategory}
            onChange={(e) => setNewCategory(e.target.value)}
            className="category-input"
          />
          <button type="submit" className="category-btn">
            ➕ Add Category
          </button>
        </form>
      </div>

      {/* Category Dropdown */}
      <div className="dropdown-box">
        <label>Select Category:</label>
        <select>
          <option value="">-- Choose Category --</option>
          {Array.isArray(categories) &&
            categories.map((cat) => (
              <option key={cat._id} value={cat.name}>
                {cat.name}
              </option>
            ))}
        </select>
      </div>

      {/* Graph Section */}
      <div className="chart-section">
        <h3>Price vs Stock Analysis</h3>
        {chartData.length > 0 ? (
          <ResponsiveContainer width="100%" height={400}>
            <BarChart data={chartData}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="name" />
              <YAxis />
              <Tooltip />
              <Legend />
              <Bar dataKey="price" fill="#8884d8" />
              <Bar dataKey="stock" fill="#82ca9d" />
            </BarChart>
          </ResponsiveContainer>
        ) : (
          <p style={{ textAlign: "center", marginTop: "20px" }}>
            No data available for graph
          </p>
        )}
      </div>

      {/* Product List Section */}
      <div className="product-table">
        <h3>🛍 Product List</h3>
        {Array.isArray(productList) && productList.length > 0 ? (
          <table>
            <thead>
              <tr>
                <th>Sr.</th>
                <th>Image</th>
                <th>Name</th>
                <th>Category</th>
                <th>Price (₹)</th>
                <th>Stock</th>
              </tr>
            </thead>
            <tbody>
              {productList.map((item, index) => (
                <tr key={item._id}>
                  <td>{index + 1}</td>
                  <td>
                    <img
                      src={item.image || "https://via.placeholder.com/60"}
                      alt={item.name}
                      className="product-img"
                    />
                  </td>
                  <td>{item.name}</td>
                  <td>{item.category || "N/A"}</td>
                  <td>{item.price || "—"}</td>
                  <td>{item.stock || "—"}</td>
                </tr>
              ))}
            </tbody>
          </table>
        ) : (
          <p style={{ textAlign: "center", marginTop: "20px" }}>
            No products found
          </p>
        )}
      </div>
    </div>
  );
}
